468	/// Process exit status.
469	#[derive(Debug, Clone, Copy)]
470	pub struct ProcessStatus {
471	    code: Option<i32>,
472	    signal: Option<i32>,
473	}
474	
475	impl ProcessStatus {
476	    /// Get the exit code, or 128 + signal number if killed by signal.
477	    #[must_use]
478	    pub fn code(&self) -> i32 {
479	        self.code
480	            .or_else(|| self.signal.map(|s| 128 + s))
481	            .unwrap_or(-1)
482	    }
483	
484	    /// Check if the process exited successfully.
485	    #[must_use]
486	    pub fn success(&self) -> bool {
487	        self.code == Some(0)
488	    }
489	
490	    /// Get the signal that killed the process, if any.
491	    #[must_use]
492	    pub const fn signal(&self) -> Option<i32> {
493	        self.signal
494	    }
495	}
496	
497	impl From<std::process::ExitStatus> for ProcessStatus {
498	    fn from(status: std::process::ExitStatus) -> Self {
499	        #[cfg(unix)]
500	        {
501	            use std::os::unix::process::ExitStatusExt;
502	            Self {
503	                code: status.code(),
504	                signal: status.signal(),
505	            }
506	        }
507	
508	        #[cfg(not(unix))]
509	        {
510	            Self {
511	                code: status.code(),
512	                signal: None,
513	            }
514	        }
515	    }
516	}
