537	    #[test]
538	    fn drop_privileges_noop_when_no_user_or_group() {
539	        let policy = policy_with_process(ProcessPolicy {
540	            run_as_user: None,
541	            run_as_group: None,
542	        });
543	        if nix::unistd::geteuid().is_root() {
544	            // As root, drop_privileges falls back to "sandbox:sandbox".
545	            // If that user exists, it succeeds; if not (e.g. CI), it
546	            // must error rather than silently keep root.
547	            let has_sandbox = User::from_name("sandbox").ok().flatten().is_some();
548	            assert_eq!(drop_privileges(&policy).is_ok(), has_sandbox);
549	        } else {
550	            assert!(drop_privileges(&policy).is_ok());
551	        }
552	    }
