//! Landlock filesystem sandboxing.

use crate::policy::{LandlockCompatibility, SandboxPolicy};
use landlock::{
    ABI, Access, AccessFs, CompatLevel, Compatible, PathBeneath, PathFd, PathFdError, Ruleset,
    RulesetAttr, RulesetCreatedAttr,
};
use miette::{IntoDiagnostic, Result};
use std::os::fd::{AsRawFd, OwnedFd};
use std::path::{Path, PathBuf};
use tracing::debug;

/// Pre-opened file descriptors for Landlock path rules.
///
/// Opening path FDs via `open(path, O_PATH | O_CLOEXEC)` requires filesystem
/// access privileges.  After [`super::drop_privileges`] switches to an
/// unprivileged user, those opens would fail (permission denied), causing the
/// entire Landlock ruleset to fall back to `Ok(())` in `best_effort` mode and
/// run the sandbox unconfined.
///
/// Callers must open these FDs *before* dropping privileges so the Landlock
/// ruleset always receives valid directory descriptors.
pub struct LandlockFds {
    /// (path, fd) pairs for read-only rules.
    ro: Vec<(PathBuf, OwnedFd)>,
    /// (path, fd) pairs for read-write rules.
    rw: Vec<(PathBuf, OwnedFd)>,
}

/// Pre-open `O_PATH` file descriptors for every path that the Landlock policy
/// references.  Call this **before** `drop_privileges()` so the FDs are opened
/// by the initial (privileged) process identity.
pub fn prepare_fds(policy: &SandboxPolicy, workdir: Option<&str>) -> LandlockFds {
    let read_only = policy.filesystem.read_only.clone();
    let mut read_write = policy.filesystem.read_write.clone();

    if policy.filesystem.include_workdir
        && let Some(dir) = workdir
    {
        let workdir_path = PathBuf::from(dir);
        if !read_write.contains(&workdir_path) {
            read_write.push(workdir_path);
        }
    }

    let ro = read_only
        .iter()
        .filter_map(|p| open_path_fd(p).map(|fd| (p.clone(), fd)))
        .collect();
    let rw = read_write
        .iter()
        .filter_map(|p| open_path_fd(p).map(|fd| (p.clone(), fd)))
        .collect();

    LandlockFds { ro, rw }
}

/// Open a path as `O_PATH | O_CLOEXEC`.
///
/// Returns `None` if the path does not exist — this allows baseline paths
/// that are absent from a particular container image to be silently skipped
/// (matching the previous `BestEffort` behaviour).
fn open_path_fd(path: &Path) -> Option<OwnedFd> {
    let c_path = std::ffi::CString::new(path.as_os_str().as_encoded_bytes()).ok()?;
    // SAFETY: FFI call with null-terminated C string and zero flags.
    #[allow(unsafe_code)]
    let raw_fd = unsafe { libc::open(c_path.as_ptr(), libc::O_PATH | libc::O_CLOEXEC) };
    if raw_fd < 0 {
        // Only suppress NotFound — anything else (EACCES, ELOOP, etc.) should
        // surface to operators.  We still return None so the caller can proceed,
        // but the ruleset builder will report zero valid paths and fail fast in
        // BestEffort (or HardRequirement).
        let err = std::io::Error::last_os_error();
        if err.kind() == std::io::ErrorKind::NotFound {
            debug!(
                path = %path.display(),
                "Skipping non-existent Landlock path (pre-open before drop_privileges)"
            );
        } else {
            openshell_ocsf::ocsf_emit!(
                openshell_ocsf::ConfigStateChangeBuilder::new(crate::ocsf_ctx())
                    .severity(openshell_ocsf::SeverityId::Low)
                    .status(openshell_ocsf::StatusId::Failure)
                    .state(openshell_ocsf::StateId::Other, "degraded")
                    .message(format!(
                        "Unable to pre-open Landlock path [path:{} error:{err}]",
                        path.display(),
                    ))
                    .build()
            );
        }
        return None;
    }
    // SAFETY: raw_fd is a valid open file descriptor.
    #[allow(unsafe_code)]
    Some(unsafe { OwnedFd::from_raw_fd(raw_fd) })
}

/// Apply Landlock filesystem restrictions.
///
/// Uses `fds` (pre-opened by `prepare_fds()` before privilege drop) when
/// provided.  Falls back to opening paths inline if `fds` is `None`, which
/// preserves backward compatibility for call sites that do not use the
/// two-phase approach.
pub fn apply(
    policy: &SandboxPolicy,
    workdir: Option<&str>,
    fds: Option<&LandlockFds>,
) -> Result<()> {
    let read_only = policy.filesystem.read_only.clone();
    let mut read_write = policy.filesystem.read_write.clone();

    if policy.filesystem.include_workdir
        && let Some(dir) = workdir
    {
        let workdir_path = PathBuf::from(dir);
        if !read_write.contains(&workdir_path) {
            read_write.push(workdir_path);
        }
    }

    if read_only.is_empty() && read_write.is_empty() {
        return Ok(());
    }

    let total_paths = read_only.len() + read_write.len();
    let abi = ABI::V2;
    openshell_ocsf::ocsf_emit!(
        openshell_ocsf::ConfigStateChangeBuilder::new(crate::ocsf_ctx())
            .severity(openshell_ocsf::SeverityId::Informational)
            .status(openshell_ocsf::StatusId::Success)
            .state(openshell_ocsf::StateId::Enabled, "applying")
            .message(format!(
                "Applying Landlock filesystem sandbox [abi:{abi:?} compat:{:?} ro:{} rw:{}]",
                policy.landlock.compatibility,
                read_only.len(),
                read_write.len(),
            ))
            .build()
    );

    let compatibility = &policy.landlock.compatibility;

    let result: Result<()> = (|| {
        let access_all = AccessFs::from_all(abi);
        let access_read = AccessFs::from_read(abi);

        let mut ruleset = Ruleset::default();
        ruleset = ruleset
            .set_compatibility(compat_level(compatibility))
            .handle_access(access_all)
            .into_diagnostic()?;

        let mut ruleset = ruleset.create().into_diagnostic()?;
        let mut rules_applied: usize = 0;

        // Use pre-opened FDs when available (two-phase: opened as root before
        // drop_privileges).  Otherwise, fall back to opening paths inline.
        if let Some(fds) = fds {
            for (path, fd) in &fds.ro {
                debug!(path = %path.display(), "Landlock allow read-only (pre-opened fd:{})", fd.as_raw_fd());
                ruleset = ruleset
                    .add_rule(PathBeneath::new(fd.as_fd().try_clone_to_owned().into_diagnostic()?, access_read))
                    .into_diagnostic()?;
                rules_applied += 1;
            }

            for (path, fd) in &fds.rw {
                debug!(path = %path.display(), "Landlock allow read-write (pre-opened fd:{})", fd.as_raw_fd());
                ruleset = ruleset
                    .add_rule(PathBeneath::new(fd.as_fd().try_clone_to_owned().into_diagnostic()?, access_all))
                    .into_diagnostic()?;
                rules_applied += 1;
            }

            // Drop the pre-opened FDs now that they've been duplicated into
            // the PathBeneath rules via try_clone_to_owned().  The Ruleset holds
            // its own copies of each fd internally.
        } else {
            for path in &read_only {
                if let Some(path_fd) = try_open_path(path, compatibility)? {
                    debug!(path = %path.display(), "Landlock allow read-only");
                    ruleset = ruleset
                        .add_rule(PathBeneath::new(path_fd, access_read))
                        .into_diagnostic()?;
                    rules_applied += 1;
                }
            }

            for path in &read_write {
                if let Some(path_fd) = try_open_path(path, compatibility)? {
                    debug!(path = %path.display(), "Landlock allow read-write");
                    ruleset = ruleset
                        .add_rule(PathBeneath::new(path_fd, access_all))
                        .into_diagnostic()?;
                    rules_applied += 1;
                }
            }
        }

        if rules_applied == 0 {
            return Err(miette::miette!(
                "Landlock ruleset has zero valid paths — all {} path(s) failed to open. \
                 Refusing to apply an empty ruleset that would block all filesystem access.",
                total_paths,
            ));
        }

        let skipped = total_paths - rules_applied;
        openshell_ocsf::ocsf_emit!(
            openshell_ocsf::ConfigStateChangeBuilder::new(crate::ocsf_ctx())
                .severity(openshell_ocsf::SeverityId::Informational)
                .status(openshell_ocsf::StatusId::Success)
                .state(openshell_ocsf::StateId::Enabled, "built")
                .message(format!(
                    "Landlock ruleset built [rules_applied:{rules_applied} skipped:{skipped}]"
                ))
                .build()
        );

        ruleset.restrict_self().into_diagnostic()?;
        Ok(())
    })();

    if let Err(err) = result {
        if matches!(compatibility, LandlockCompatibility::BestEffort) {
            openshell_ocsf::ocsf_emit!(
                openshell_ocsf::DetectionFindingBuilder::new(crate::ocsf_ctx())
                    .activity(openshell_ocsf::ActivityId::Open)
                    .severity(openshell_ocsf::SeverityId::High)
                    .confidence(openshell_ocsf::ConfidenceId::High)
                    .is_alert(true)
                    .finding_info(
                        openshell_ocsf::FindingInfo::new(
                            "landlock-unavailable",
                            "Landlock Filesystem Sandbox Unavailable",
                        )
                        .with_desc(&format!(
                            "Running WITHOUT filesystem restrictions: {err}. \
                             Set landlock.compatibility to 'hard_requirement' to make this fatal."
                        )),
                    )
                    .message(format!("Landlock filesystem sandbox unavailable: {err}"))
                    .build()
            );
            return Ok(());
        }
        return Err(err);
    }

    Ok(())
}

