58	    LandlockFds { ro, rw }
59	}
60	
61	/// Open a path as `O_PATH | O_CLOEXEC`.
62	///
63	/// Returns `None` if the path does not exist — this allows baseline paths
64	/// that are absent from a particular container image to be silently skipped
65	/// (matching the previous `BestEffort` behaviour).
66	fn open_path_fd(path: &Path) -> Option<OwnedFd> {
67	    let c_path = std::ffi::CString::new(path.as_os_str().as_encoded_bytes()).ok()?;
68	    // SAFETY: FFI call with null-terminated C string and zero flags.
69	    #[allow(unsafe_code)]
70	    let raw_fd = unsafe { libc::open(c_path.as_ptr(), libc::O_PATH | libc::O_CLOEXEC) };
71	    if raw_fd < 0 {
72	        // Only suppress NotFound — anything else (EACCES, ELOOP, etc.) should
73	        // surface to operators.  We still return None so the caller can proceed,
74	        // but the ruleset builder will report zero valid paths and fail fast in
75	        // BestEffort (or HardRequirement).
76	        let err = std::io::Error::last_os_error();
77	        if err.kind() == std::io::ErrorKind::NotFound {
78	            debug!(
79	                path = %path.display(),
80	                "Skipping non-existent Landlock path (pre-open before drop_privileges)"
81	            );
82	        } else {
83	            openshell_ocsf::ocsf_emit!(
84	                openshell_ocsf::ConfigStateChangeBuilder::new(crate::ocsf_ctx())
85	                    .severity(openshell_ocsf::SeverityId::Low)
86	                    .status(openshell_ocsf::StatusId::Failure)
87	                    .state(openshell_ocsf::StateId::Other, "degraded")
88	                    .message(format!(
89	                        "Unable to pre-open Landlock path [path:{} error:{err}]",
90	                        path.display(),
91	                    ))
92	                    .build()
93	            );
94	        }
95	        return None;
96	    }
97	    // SAFETY: raw_fd is a valid open file descriptor.
98	    #[allow(unsafe_code)]
99	    Some(unsafe { OwnedFd::from_raw_fd(raw_fd) })
100	}
101	
102	/// Apply Landlock filesystem restrictions.
103	///
104	/// Uses `fds` (pre-opened by `prepare_fds()` before privilege drop) when
105	/// provided.  Falls back to opening paths inline if `fds` is `None`, which
106	/// preserves backward compatibility for call sites that do not use the
107	/// two-phase approach.
108	pub fn apply(
109	    policy: &SandboxPolicy,
110	    workdir: Option<&str>,
111	    fds: Option<&LandlockFds>,
112	) -> Result<()> {
113	    let read_only = policy.filesystem.read_only.clone();
114	    let mut read_write = policy.filesystem.read_write.clone();
115	
116	    if policy.filesystem.include_workdir
117	        && let Some(dir) = workdir
118	    {
119	        let workdir_path = PathBuf::from(dir);
120	        if !read_write.contains(&workdir_path) {
121	            read_write.push(workdir_path);
122	        }
123	    }
124	
125	    if read_only.is_empty() && read_write.is_empty() {
126	        return Ok(());
127	    }
128	
129	    let total_paths = read_only.len() + read_write.len();
130	    let abi = ABI::V2;
131	    openshell_ocsf::ocsf_emit!(
132	        openshell_ocsf::ConfigStateChangeBuilder::new(crate::ocsf_ctx())
133	            .severity(openshell_ocsf::SeverityId::Informational)
134	            .status(openshell_ocsf::StatusId::Success)
135	            .state(openshell_ocsf::StateId::Enabled, "applying")
136	            .message(format!(
137	                "Applying Landlock filesystem sandbox [abi:{abi:?} compat:{:?} ro:{} rw:{}]",
138	                policy.landlock.compatibility,
139	                read_only.len(),
140	                read_write.len(),
141	            ))
142	            .build()
143	    );
144	
145	    let compatibility = &policy.landlock.compatibility;
146	
147	    let result: Result<()> = (|| {
148	        let access_all = AccessFs::from_all(abi);
149	        let access_read = AccessFs::from_read(abi);
150	
151	        let mut ruleset = Ruleset::default();
152	        ruleset = ruleset
153	            .set_compatibility(compat_level(compatibility))
154	            .handle_access(access_all)
155	            .into_diagnostic()?;
156	
157	        let mut ruleset = ruleset.create().into_diagnostic()?;
158	        let mut rules_applied: usize = 0;
159	
160	        // Use pre-opened FDs when available (two-phase: opened as root before
161	        // drop_privileges).  Otherwise, fall back to opening paths inline.
162	        if let Some(fds) = fds {
163	            for (path, fd) in &fds.ro {
164	                debug!(path = %path.display(), "Landlock allow read-only (pre-opened fd:{})", fd.as_raw_fd());
165	                ruleset = ruleset
166	                    .add_rule(PathBeneath::new(fd.as_fd().try_clone_to_owned().into_diagnostic()?, access_read))
167	                    .into_diagnostic()?;
168	                rules_applied += 1;
169	            }
170	
171	            for (path, fd) in &fds.rw {
172	                debug!(path = %path.display(), "Landlock allow read-write (pre-opened fd:{})", fd.as_raw_fd());
173	                ruleset = ruleset
174	                    .add_rule(PathBeneath::new(fd.as_fd().try_clone_to_owned().into_diagnostic()?, access_all))
175	                    .into_diagnostic()?;
176	                rules_applied += 1;
177	            }
178	
179	            // Drop the pre-opened FDs now that they've been duplicated into
180	            // the PathBeneath rules via try_clone_to_owned().  The Ruleset holds
181	            // its own copies of each fd internally.
182	        } else {
183	            for path in &read_only {
184	                if let Some(path_fd) = try_open_path(path, compatibility)? {
185	                    debug!(path = %path.display(), "Landlock allow read-only");
186	                    ruleset = ruleset
187	                        .add_rule(PathBeneath::new(path_fd, access_read))
188	                        .into_diagnostic()?;
189	                    rules_applied += 1;
190	                }
191	            }
192	
193	            for path in &read_write {
194	                if let Some(path_fd) = try_open_path(path, compatibility)? {
195	                    debug!(path = %path.display(), "Landlock allow read-write");
196	                    ruleset = ruleset
197	                        .add_rule(PathBeneath::new(path_fd, access_all))
198	                        .into_diagnostic()?;
199	                    rules_applied += 1;
200	                }
201	            }
202	        }
203	
204	        if rules_applied == 0 {
205	            return Err(miette::miette!(
206	                "Landlock ruleset has zero valid paths — all {} path(s) failed to open. \
207	                 Refusing to apply an empty ruleset that would block all filesystem access.",
208	                total_paths,
209	            ));
210	        }
211	
212	        let skipped = total_paths - rules_applied;
213	        openshell_ocsf::ocsf_emit!(
214	            openshell_ocsf::ConfigStateChangeBuilder::new(crate::ocsf_ctx())
215	                .severity(openshell_ocsf::SeverityId::Informational)
216	                .status(openshell_ocsf::StatusId::Success)
217	                .state(openshell_ocsf::StateId::Enabled, "built")
218	                .message(format!(
219	                    "Landlock ruleset built [rules_applied:{rules_applied} skipped:{skipped}]"
220	                ))
221	                .build()
222	        );
223	
224	        ruleset.restrict_self().into_diagnostic()?;
225	        Ok(())
226	    })();
227	
228	    if let Err(err) = result {
229	        if matches!(compatibility, LandlockCompatibility::BestEffort) {
230	            openshell_ocsf::ocsf_emit!(
231	                openshell_ocsf::DetectionFindingBuilder::new(crate::ocsf_ctx())
232	                    .activity(openshell_ocsf::ActivityId::Open)
233	                    .severity(openshell_ocsf::SeverityId::High)
234	                    .confidence(openshell_ocsf::ConfidenceId::High)
235	                    .is_alert(true)
236	                    .finding_info(
237	                        openshell_ocsf::FindingInfo::new(
238	                            "landlock-unavailable",
239	                            "Landlock Filesystem Sandbox Unavailable",
240	                        )
241	                        .with_desc(&format!(
242	                            "Running WITHOUT filesystem restrictions: {err}. \
243	                             Set landlock.compatibility to 'hard_requirement' to make this fatal."
244	                        )),
245	                    )
246	                    .message(format!("Landlock filesystem sandbox unavailable: {err}"))
247	                    .build()
248	            );
249	            return Ok(());
250	        }
251	        return Err(err);
252	    }
253	
254	    Ok(())
255	}
256	
257	/// Attempt to open a path for Landlock rule creation.
258	///
259	/// In `BestEffort` mode, inaccessible paths (missing, permission denied, symlink
260	/// loops, etc.) are skipped with a warning and `Ok(None)` is returned so the
261	/// caller can continue building the ruleset from the remaining valid paths.
262	///
263	/// In `HardRequirement` mode, any failure is fatal — the caller propagates the
264	/// error, which ultimately aborts sandbox startup.
265	fn try_open_path(path: &Path, compatibility: &LandlockCompatibility) -> Result<Option<PathFd>> {
266	    match PathFd::new(path) {
267	        Ok(fd) => Ok(Some(fd)),
268	        Err(err) => {
269	            let reason = classify_path_fd_error(&err);
270	            let is_not_found = matches!(
271	                &err,
272	                PathFdError::OpenCall { source, .. }
273	                    if source.kind() == std::io::ErrorKind::NotFound
274	            );
275	            match compatibility {
276	                LandlockCompatibility::BestEffort => {
277	                    // NotFound is expected for stale baseline paths (e.g.
278	                    // /app baked into the server-stored policy but absent
279	                    // in this container image).  Log at debug! to avoid
280	                    // polluting SSH exec stdout — the pre_exec hook
281	                    // inherits the tracing subscriber whose writer targets
282	                    // fd 1 (the pipe/PTY).
283	                    //
284	                    // Other errors (permission denied, symlink loops, etc.)
285	                    // are genuinely unexpected and logged at warn!.
286	                    if is_not_found {
287	                        debug!(
288	                            path = %path.display(),
289	                            reason,
290	                            "Skipping non-existent Landlock path (best-effort mode)"
291	                        );
292	                    } else {
293	                        openshell_ocsf::ocsf_emit!(
294	                            openshell_ocsf::ConfigStateChangeBuilder::new(crate::ocsf_ctx())
295	                                .severity(openshell_ocsf::SeverityId::Medium)
296	                                .status(openshell_ocsf::StatusId::Failure)
297	                                .state(openshell_ocsf::StateId::Other, "degraded")
298	                                .message(format!(
299	                                    "Skipping inaccessible Landlock path (best-effort) [path:{} error:{err}]",
300	                                    path.display()
301	                                ))
302	                                .build()
303	                        );
304	                    }
305	                    Ok(None)
306	                }
307	                LandlockCompatibility::HardRequirement => Err(miette::miette!(
308	                    "Landlock path unavailable in hard_requirement mode: {} ({}): {}",
309	                    path.display(),
310	                    reason,
311	                    err,
312	                )),
313	            }
314	        }
315	    }
316	}
317	
318	/// Classify a [`PathFdError`] into a human-readable reason.
319	///
320	/// `PathFd::new()` wraps `open(path, O_PATH | O_CLOEXEC)` which can fail for
321	/// several reasons beyond simple non-existence. The `PathFdError::OpenCall`
322	/// variant wraps the underlying `std::io::Error`.
323	fn classify_path_fd_error(err: &PathFdError) -> &'static str {
324	    match err {
325	        PathFdError::OpenCall { source, .. } => classify_io_error(source),
326	        // PathFdError is #[non_exhaustive], handle future variants gracefully.
327	        _ => "unexpected error",
328	    }
329	}
330	
331	/// Classify a `std::io::Error` into a human-readable reason string.
332	fn classify_io_error(err: &std::io::Error) -> &'static str {
333	    match err.kind() {
334	        std::io::ErrorKind::NotFound => "path does not exist",
335	        std::io::ErrorKind::PermissionDenied => "permission denied",
336	        _ => match err.raw_os_error() {
337	            Some(40) => "too many symlink levels",           // ELOOP
338	            Some(36) => "path name too long",                // ENAMETOOLONG
339	            Some(20) => "path component is not a directory", // ENOTDIR
340	            _ => "unexpected error",
341	        },
342	    }
343	}
344	
345	fn compat_level(level: &LandlockCompatibility) -> CompatLevel {
346	    match level {
347	        LandlockCompatibility::BestEffort => CompatLevel::BestEffort,
348	        LandlockCompatibility::HardRequirement => CompatLevel::HardRequirement,
349	    }
350	}
351	
352	#[cfg(test)]
353	mod tests {
354	    use super::*;
355	
356	    #[test]
357	    fn try_open_path_best_effort_returns_none_for_missing_path() {
358	        let result = try_open_path(
359	            &PathBuf::from("/nonexistent/openshell/test/path"),
360	            &LandlockCompatibility::BestEffort,
361	        );
362	        assert!(result.is_ok());
363	        assert!(result.unwrap().is_none());
364	    }
365	
366	    #[test]
367	    fn try_open_path_hard_requirement_errors_for_missing_path() {
368	        let result = try_open_path(
369	            &PathBuf::from("/nonexistent/openshell/test/path"),
370	            &LandlockCompatibility::HardRequirement,
371	        );
372	        assert!(result.is_err());
373	        let err_msg = result.unwrap_err().to_string();
374	        assert!(
375	            err_msg.contains("hard_requirement"),
376	            "error should mention hard_requirement mode: {err_msg}"
377	        );
378	        assert!(
379	            err_msg.contains("does not exist"),
380	            "error should include the classified reason: {err_msg}"
381	        );
382	    }
383	
384	    #[test]
385	    fn try_open_path_succeeds_for_existing_path() {
386	        let dir = tempfile::tempdir().unwrap();
387	        let result = try_open_path(dir.path(), &LandlockCompatibility::BestEffort);
388	        assert!(result.is_ok());
389	        assert!(result.unwrap().is_some());
390	    }
391	
392	    #[test]
393	    fn classify_not_found() {
394	        let err = std::io::Error::from_raw_os_error(libc::ENOENT);
395	        assert_eq!(classify_io_error(&err), "path does not exist");
396	    }
397	
398	    #[test]
399	    fn classify_permission_denied() {
400	        let err = std::io::Error::from_raw_os_error(libc::EACCES);
401	        assert_eq!(classify_io_error(&err), "permission denied");
402	    }
403	
404	    #[test]
405	    fn classify_symlink_loop() {
406	        let err = std::io::Error::from_raw_os_error(libc::ELOOP);
407	        assert_eq!(classify_io_error(&err), "too many symlink levels");
408	    }
409	
410	    #[test]
411	    fn classify_name_too_long() {
412	        let err = std::io::Error::from_raw_os_error(libc::ENAMETOOLONG);
413	        assert_eq!(classify_io_error(&err), "path name too long");
414	    }
415	
416	    #[test]
417	    fn classify_not_a_directory() {
418	        let err = std::io::Error::from_raw_os_error(libc::ENOTDIR);
419	        assert_eq!(classify_io_error(&err), "path component is not a directory");
420	    }
421	
422	    #[test]
423	    fn classify_unknown_error() {
424	        let err = std::io::Error::from_raw_os_error(libc::EIO);
425	        assert_eq!(classify_io_error(&err), "unexpected error");
426	    }
427	
428	    #[test]
429	    fn classify_path_fd_error_extracts_io_error() {
430	        // Use PathFd::new on a non-existent path to get a real PathFdError
431	        // (the OpenCall variant is #[non_exhaustive] and can't be constructed directly).
432	        let err = PathFd::new("/nonexistent/openshell/classify/test").unwrap_err();
433	        assert_eq!(classify_path_fd_error(&err), "path does not exist");
434	    }
435	}
